import {
  CustomElement,
  Prop,
  Listen,
  Dispatch,
  DispatchEmitter,
} from 'custom-elements-ts';

@CustomElement({
  tag: 'cts-message',
  template: `
    <div class="row" role="button" tabindex="0" aria-label="Copy install command to clipboard">
      <span class="prompt" aria-hidden="true">$</span>
      <code class="cmd"></code>
      <span class="icon" aria-hidden="true">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
          <rect x="9" y="9" width="13" height="13" rx="1"/>
          <path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/>
        </svg>
      </span>
    </div>
  `,
  style: `:host {
  display: block;
  margin: 18px 22px 6px;
  --bg: rgba(255, 255, 255, 0.025);
  --bg-hover: rgba(255, 255, 255, 0.05);
  --line: rgba(255, 255, 255, 0.10);
  --line-hover: rgba(49, 120, 198, 0.45);
  --fg: #e6ecf3;
  --fg-prompt: #9cc0eb;
  --fg-icon: #5b6370;
  --fg-icon-hover: #9cc0eb;
}

.row {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr) auto;
  align-items: center;
  gap: 10px;
  padding: 13px 14px;
  font-family: "Geist Mono", "JetBrains Mono", ui-monospace, SFMono-Regular,
               Menlo, Consolas, "Courier New", monospace;
  font-size: 13.5px;
  font-weight: 500;
  color: var(--fg);
  background: var(--bg);
  border: 1px solid var(--line);
  border-radius: 3px;
  cursor: pointer;
  user-select: none;
  outline: none;
  transition: background 220ms cubic-bezier(0.22, 1, 0.36, 1),
              border-color 220ms cubic-bezier(0.22, 1, 0.36, 1),
              transform 140ms cubic-bezier(0.22, 1, 0.36, 1);
}

.row:hover {
  background: var(--bg-hover);
  border-color: var(--line-hover);
}

.row:active { transform: translateY(1px); }

.row:focus-visible {
  border-color: var(--line-hover);
  box-shadow: 0 0 0 2px rgba(49, 120, 198, 0.45);
}

.prompt {
  color: var(--fg-prompt);
  font-weight: 600;
  opacity: 0.95;
}

.cmd {
  font-family: inherit;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  min-width: 0;
}

.icon {
  display: grid;
  place-items: center;
  color: var(--fg-icon);
  transition: color 220ms cubic-bezier(0.22, 1, 0.36, 1);
}

.icon svg {
  width: 14px;
  height: 14px;
  display: block;
}

.row:hover .icon { color: var(--fg-icon-hover); }
`,
})
export class MessageElement extends HTMLElement {
  @Prop() message: string;

  @Dispatch('cts:toast') toast: DispatchEmitter;

  @Listen('click')
  async handleClick() {
    const text = this.message ?? '';
    let ok = true;
    try {
      if (navigator.clipboard?.writeText) {
        await navigator.clipboard.writeText(text);
      } else {
        ok = this.fallbackCopy(text);
      }
    } catch {
      ok = false;
    }
    this.toast.emit({
      bubbles: true,
      composed: true,
      detail: ok
        ? { title: 'Copied to clipboard', message: text, kind: 'success' }
        : { title: "Couldn't copy", message: 'Copy the command manually.', kind: 'error' },
    });
  }

  @Listen('keydown')
  handleKey(e: KeyboardEvent) {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      this.handleClick();
    }
  }

  connectedCallback() {
    const cmd = this.shadowRoot?.querySelector('.cmd');
    if (cmd) cmd.textContent = this.message;
  }

  // Older browsers / non-secure contexts: fall back to the legacy copy path.
  private fallbackCopy(text: string): boolean {
    const ta = document.createElement('textarea');
    ta.value = text;
    ta.style.position = 'fixed';
    ta.style.opacity = '0';
    document.body.appendChild(ta);
    ta.select();
    let ok = false;
    try { ok = document.execCommand('copy'); } catch { ok = false; }
    document.body.removeChild(ta);
    return ok;
  }
}
